#include<bits/stdc++.h>
using namespace std;

int c[1000001];

int main()
{
	int n,a,b,ans[100001],mina=9999;
    scanf("%d%d%d",&n,&a,&b);
    memset(ans,0,sizeof(ans));
    for(int i=1;i<=n;i++)
	{
		scanf("%d",&c[i]);
	}
	sort(c+1,c+n+1);
    for(int i=1;i<=n;i++)
	{
    	for(int j=1;j<=n;j++)
		{
    		if(c[j]<c[i])
    		{
    			ans[i]+=(c[i]-c[j])*a;
    		}
    		else
    		{
    			ans[i]+=(c[j]-c[i])*b;
    		}
		}
	}
	for(int i=1;i<=n;i++)
	{
		mina=min(mina,ans[i]);
	}
	printf("%d",mina);
    return 0;
}
